## Objective
Benchmark glamour's markdown parsing and rendering pipeline with various document sizes and complexity levels. These benchmarks will guide optimization and detect regressions in the rendering path.

## Detailed Requirements

### 1. Document Parsing Benchmarks
```rust
use criterion::{black_box, criterion_group, Criterion, Throughput, BenchmarkId};
use glamour::{render, StyleConfig};

const SMALL_DOC: &str = include_str!("fixtures/small.md");   // ~100 lines
const MEDIUM_DOC: &str = include_str!("fixtures/medium.md"); // ~1000 lines
const LARGE_DOC: &str = include_str!("fixtures/large.md");   // ~10000 lines

fn bench_parsing(c: &mut Criterion) {
    let mut group = c.benchmark_group("glamour/parsing");

    for (name, doc) in [
        ("small", SMALL_DOC),
        ("medium", MEDIUM_DOC),
        ("large", LARGE_DOC),
    ] {
        group.throughput(Throughput::Bytes(doc.len() as u64));
        group.bench_with_input(
            BenchmarkId::new("parse", name),
            doc,
            |b, doc| b.iter(|| black_box(pulldown_cmark::Parser::new(doc).count())),
        );
    }

    group.finish();
}
```

### 2. Full Rendering Benchmarks
```rust
fn bench_full_render(c: &mut Criterion) {
    let mut group = c.benchmark_group("glamour/render");

    for (name, doc) in [
        ("small", SMALL_DOC),
        ("medium", MEDIUM_DOC),
        ("large", LARGE_DOC),
    ] {
        group.throughput(Throughput::Bytes(doc.len() as u64));
        group.bench_with_input(
            BenchmarkId::new("full", name),
            doc,
            |b, doc| b.iter(|| black_box(render(doc))),
        );
    }

    group.finish();
}
```

### 3. Element-Specific Benchmarks
```rust
fn bench_elements(c: &mut Criterion) {
    let mut group = c.benchmark_group("glamour/elements");

    // Headers
    let headers = (1..=6)
        .map(|n| format!("{} Header Level {}\n\n", "#".repeat(n), n))
        .collect::<String>()
        .repeat(100);
    group.bench_function("headers", |b| {
        b.iter(|| black_box(render(&headers)))
    });

    // Lists
    let list = (0..100)
        .map(|i| format!("- Item {}\n", i))
        .collect::<String>();
    group.bench_function("unordered_list_100", |b| {
        b.iter(|| black_box(render(&list)))
    });

    let nested_list = (0..50)
        .map(|i| format!("- Item {}\n  - Nested {}\n    - Deep {}\n", i, i, i))
        .collect::<String>();
    group.bench_function("nested_list", |b| {
        b.iter(|| black_box(render(&nested_list)))
    });

    // Code blocks
    let code_blocks = r#"
```rust
fn main() {
    println!("Hello");
}
```
"#.repeat(50);
    group.bench_function("code_blocks_50", |b| {
        b.iter(|| black_box(render(&code_blocks)))
    });

    // Links and emphasis
    let links = (0..100)
        .map(|i| format!("[Link {}](https://example.com/{}) and **bold** and *italic*\n", i, i))
        .collect::<String>();
    group.bench_function("links_emphasis_100", |b| {
        b.iter(|| black_box(render(&links)))
    });

    // Tables (when implemented)
    let table = r#"
| Col 1 | Col 2 | Col 3 |
|-------|-------|-------|
| A | B | C |
"#.repeat(50);
    group.bench_function("tables_50", |b| {
        b.iter(|| black_box(render(&table)))
    });

    group.finish();
}
```

### 4. Configuration Impact Benchmarks
```rust
fn bench_config_impact(c: &mut Criterion) {
    let mut group = c.benchmark_group("glamour/config");

    let doc = MEDIUM_DOC;

    // Default config
    group.bench_function("default_config", |b| {
        b.iter(|| black_box(render(doc)))
    });

    // With syntax highlighting (if enabled)
    #[cfg(feature = "syntax-highlighting")]
    {
        let config = StyleConfig::default().syntax_theme("base16-ocean.dark");
        group.bench_function("with_syntax_highlighting", |b| {
            b.iter(|| black_box(glamour::render_with_config(doc, config.clone())))
        });
    }

    // Custom styles
    let custom = StyleConfig::default()
        .header_style(lipgloss::Style::new().bold(true).foreground(Color::rgb(255, 0, 0)));
    group.bench_function("custom_styles", |b| {
        b.iter(|| black_box(glamour::render_with_config(doc, custom.clone())))
    });

    group.finish();
}
```

### 5. Memory Allocation Benchmarks
```rust
fn bench_memory(c: &mut Criterion) {
    let mut group = c.benchmark_group("glamour/memory");

    // Track allocations for different document sizes
    for (name, doc) in [("small", SMALL_DOC), ("medium", MEDIUM_DOC)] {
        group.bench_function(format!("alloc_{}", name), |b| {
            b.iter_custom(|iters| {
                let start_alloc = GLOBAL_ALLOCATOR.allocated();
                for _ in 0..iters {
                    let _ = black_box(render(doc));
                }
                let end_alloc = GLOBAL_ALLOCATOR.allocated();
                // Return total bytes allocated
                std::time::Duration::from_nanos((end_alloc - start_alloc) as u64)
            })
        });
    }

    group.finish();
}
```

